+/* Minimal SVG string fixups + sanitization to mitigate DOM-based XSS.
+ *
+ * This file provides a single function `fixupSvgString` that performs a
+ * few non-destructive normalizations used by the renderer and then strips/neutralizes
+ * common vectors for SVG-based XSS:
+ *  - removes <script> elements
+ *  - removes on* event handler attributes (onclick, onload, etc.)
+ *  - neutralizes javascript:, vbscript: and data:text/html URLs in href/src/xlink:href
+ *  - removes javascript: usage in CSS url() inside style attributes
+ *
+ * The approach is conservative: we only touch obvious, dangerous patterns and
+ * otherwise return the SVG content unchanged. This keeps compatibility while
+ * addressing the reported DOM-based XSS.
+ */
+
+'use strict';
+
+function fixupSvgString(svgString) {
+  if (!svgString || typeof svgString !== 'string') return svgString;
+
+  var s = svgString;
+
+  // 1) Remove any <script>...</script> blocks (case-insensitive).
+  //    Use [\s\S]*? to match across lines non-greedily.
+  s = s.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
+
+  // 2) Remove event handler attributes such as onclick, onload, onerror, etc.
+  //    Matches patterns like: onload="..." onmouseover='...' onfocus=...
+  //    We remove the whole attribute (including value).
+  s = s.replace(/\s+on[a-z]+\s*=\s*(?:'[^']*'|"[^"]*"|[^\s>]+)/gi, '');
+
+  // 3) Neutralize javascript:, vbscript: and data:text/html URLs in href/src/xlink:href attributes.
+  //    Replace the attribute value with a harmless "#" if a dangerous scheme is detected.
+  s = s.replace(/(\b(?:href|src|xlink:href)\s*=\s*)(["']?)(\s*javascript:|s*vbscript:|s*data:\s*text\/html)[^"'\s>]*\2/gi,
